const{ChannelType:ChannelType,PermissionFlagsBits:PermissionFlagsBits}=require("discord.js");class ChannelManager{constructor(client){this.client=client,this.categoryName="NFT Alerts",this.categoryIdByGuild=new Map,this.userChannelsByGuild=new Map}async initialize(guildId){try{const guild=this.client.guilds.cache.get(guildId);if(!guild)return console.log("❌ Guild not found for channel manager"),!1;let category=guild.channels.cache.find((c=>c.type===ChannelType.GuildCategory&&c.name===this.categoryName));return category||(console.log(`📁 Creating category: ${this.categoryName}`),category=await guild.channels.create({name:this.categoryName,type:ChannelType.GuildCategory,permissionOverwrites:[{id:guild.roles.everyone.id,deny:[PermissionFlagsBits.ViewChannel]}]})),this.categoryIdByGuild.set(guild.id,category.id),await this.loadExistingChannels(guild),console.log(`✅ Channel Manager initialized with category: ${this.categoryName}`),!0}catch(error){return console.log(`❌ Failed to initialize channel manager: ${error.message}`),!1}}async loadExistingChannels(guild){try{const categoryId=this.categoryIdByGuild.get(guild.id),alertsChannels=guild.channels.cache.filter((channel=>channel.parentId===categoryId&&channel.name.startsWith("alerts-")));console.log(`🔍 Found ${alertsChannels.size} existing alerts channels`);let map=this.userChannelsByGuild.get(guild.id);map||(map=new Map,this.userChannelsByGuild.set(guild.id,map));for(const[channelId,channel]of alertsChannels)try{const userOverwrite=channel.permissionOverwrites.cache.find((overwrite=>1===overwrite.type&&overwrite.id!==guild.roles.everyone.id&&overwrite.id!==this.client.user.id));userOverwrite&&(map.set(userOverwrite.id,channelId),console.log(`📝 Loaded channel mapping: ${userOverwrite.id} -> ${channel.name}`))}catch(error){console.log(`⚠️ Could not process channel ${channel.name}: ${error.message}`)}}catch(error){console.log(`❌ Failed to load existing channels: ${error.message}`)}}async getUserChannel(userId,username,guildId){try{const guild=this.client.guilds.cache.get(guildId);if(!guild)throw new Error("Guild not available");let map=this.userChannelsByGuild.get(guild.id);if(map||(map=new Map,this.userChannelsByGuild.set(guild.id,map)),map.has(userId)){const channelId=map.get(userId),channel=this.client.channels.cache.get(channelId);if(channel)return console.log(`✅ Found existing alerts channel: ${channel.name} for user ${username}`),channel;map.delete(userId)}console.log(`🔍 Scanning for existing alerts channel for user ${username}...`);let categoryId=this.categoryIdByGuild.get(guild.id);if(!categoryId){const category=guild.channels.cache.find((c=>c.type===ChannelType.GuildCategory&&c.name===this.categoryName));category&&(categoryId=category.id,this.categoryIdByGuild.set(guild.id,categoryId))}const alertsChannels=guild.channels.cache.filter((channel=>channel.type===ChannelType.GuildText&&channel.name.startsWith("alerts-")));for(const[channelId,channel]of alertsChannels)try{if(channel.permissionOverwrites.cache.find((overwrite=>1===overwrite.type&&overwrite.id===userId&&overwrite.id!==guild.roles.everyone.id&&overwrite.id!==this.client.user.id)))return console.log(`✅ Found existing alerts channel: ${channel.name} for user ${username}`),map.set(userId,channelId),channel}catch(error){console.log(`⚠️ Could not check permissions for channel ${channel.name}: ${error.message}`)}const channelName=`alerts-${username.toLowerCase().replace(/[^a-z0-9]/g,"")}`;if(console.log(`📝 Creating new private alerts channel: ${channelName} for user ${username}`),!categoryId){categoryId=(await guild.channels.create({name:this.categoryName,type:ChannelType.GuildCategory,permissionOverwrites:[{id:guild.roles.everyone.id,deny:[PermissionFlagsBits.ViewChannel]}]})).id,this.categoryIdByGuild.set(guild.id,categoryId)}const channel=await guild.channels.create({name:channelName,type:ChannelType.GuildText,parent:categoryId,permissionOverwrites:[{id:guild.roles.everyone.id,deny:[PermissionFlagsBits.ViewChannel]},{id:userId,allow:[PermissionFlagsBits.ViewChannel,PermissionFlagsBits.ReadMessageHistory,PermissionFlagsBits.SendMessages]},{id:this.client.user.id,allow:[PermissionFlagsBits.ViewChannel,PermissionFlagsBits.SendMessages,PermissionFlagsBits.EmbedLinks,PermissionFlagsBits.AttachFiles,PermissionFlagsBits.ReadMessageHistory]}]});return map.set(userId,channel.id),await this.sendWelcomeMessage(channel,userId),console.log(`✅ Created new alerts channel: ${channel.name} (${channel.id}) for ${username}`),channel}catch(error){return console.log(`❌ Failed to get/create user channel: ${error.message}`),null}}async sendWelcomeMessage(channel,userId){try{const welcomeEmbed={title:"🔔 Welcome to Your NFT Alerts Channel!",description:`<@${userId}> This is your **exclusive** alerts channel. All your alerts from anywhere on the server will be delivered here.`,color:49151,fields:[{name:"📋 How it works",value:"• Set alerts using `/alerts` commands anywhere on the server\n• All notifications will be delivered to this channel\n• Only you can see messages in this channel\n• You have only **one** alerts channel per server",inline:!1},{name:"🎯 Alert Types Available",value:"• Collection floor price alerts\n• Specific NFT token alerts\n• Trait-based alerts (coming soon)",inline:!1},{name:"⚙️ Channel Management",value:"• Use `/alerts channel action:remove` to delete this channel\n• Deleting this channel will remove all your active alerts",inline:!1}],footer:{text:"Skadi NFT Tracker • Your personal alerts channel",icon_url:"https://via.placeholder.com/32x32?text=🤖"},timestamp:(new Date).toISOString()};await channel.send({embeds:[welcomeEmbed]})}catch(error){console.log(`❌ Failed to send welcome message: ${error.message}`)}}async sendAlert(userId,alertEmbed){try{const channelId=this.userChannels.get(userId);if(!channelId)return console.log(`⚠️ No channel found for user ${userId}`),!1;const channel=this.client.channels.cache.get(channelId);if(!channel)return console.log(`⚠️ Channel ${channelId} not found in cache`),this.userChannels.delete(userId),!1;const alertMessage=`<@${userId}> 🚨 **Alert Triggered!**`;return await channel.send({content:alertMessage,embeds:[alertEmbed]}),console.log(`✅ Alert sent to ${channel.name} for user ${userId}`),!0}catch(error){return console.log(`❌ Failed to send alert: ${error.message}`),!1}}getUserChannelId(userId){return this.userChannels.get(userId)}getAllUserChannels(){return new Map(this.userChannels)}removeUserChannel(userId){this.userChannels.delete(userId)}async deleteUserChannel(userId,guildId){try{const guild=this.client.guilds.cache.get(guildId);if(!guild)throw new Error("Guild not available");let map=this.userChannelsByGuild.get(guild.id);map||(map=new Map,this.userChannelsByGuild.set(guild.id,map));let channelId=map.get(userId);if(!channelId){let categoryId=this.categoryIdByGuild.get(guild.id);if(!categoryId){const category=guild.channels.cache.find((c=>c.type===ChannelType.GuildCategory&&c.name===this.categoryName));category&&(categoryId=category.id,this.categoryIdByGuild.set(guild.id,categoryId))}const candidates=guild.channels.cache.filter((ch=>ch.type===ChannelType.GuildText&&(!categoryId||ch.parentId===categoryId)&&ch.name.startsWith("alerts-")));for(const[cid,ch]of candidates){if(ch.permissionOverwrites?.cache?.get(userId)||ch.permissionOverwrites?.cache?.find((ow=>ow.id===userId))){channelId=cid;break}}}if(!channelId)return{ok:!1,reason:"not_found"};let channel=this.client.channels.cache.get(channelId);if(!channel)try{channel=await this.client.channels.fetch(channelId)}catch{}return channel&&await channel.delete("User requested channel removal"),map.delete(userId),console.log(`🗑️ Channel deleted for user ${userId} - alerts would be removed from database`),{ok:!0}}catch(error){return console.log(`❌ Error deleting user channel: ${error.message}`),{ok:!1,error:error.message}}}}module.exports=ChannelManager;